import{_ as a,o as s,c as l,a2 as t}from"./chunks/framework.BFVZdVmd.js";const h=JSON.parse('{"title":"Kubernetes 容器编排","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/kubernetes.md","filePath":"deploy/kubernetes.md","lastUpdated":null}'),n={name:"deploy/kubernetes.md"};function i(o,e,r,d,p,c){return s(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="kubernetes-容器编排" tabindex="-1">Kubernetes 容器编排 <a class="header-anchor" href="#kubernetes-容器编排" aria-label="Permalink to &quot;Kubernetes 容器编排&quot;">​</a></h1><p>Kubernetes（K8s）负责容器的部署、扩缩容、滚动发布和故障恢复，是大型微服务集群的运行底座。</p><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><ul><li>自动调度和管理大量容器。</li><li>滚动发布、自动扩缩容、故障自愈。</li><li>配合服务发现、负载均衡、配置管理。</li></ul><h2 id="常见组件" tabindex="-1">常见组件 <a class="header-anchor" href="#常见组件" aria-label="Permalink to &quot;常见组件&quot;">​</a></h2><ul><li><code>Kubernetes</code>：容器编排核心。</li><li><code>Helm</code>：Kubernetes 应用包管理。</li><li><code>Kustomize</code>：Kubernetes 配置管理。</li><li><code>Kubernetes Ingress</code>：流量入口。</li></ul><h2 id="典型部署链路" tabindex="-1">典型部署链路 <a class="header-anchor" href="#典型部署链路" aria-label="Permalink to &quot;典型部署链路&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>构建镜像</span></span>
<span class="line"><span>  -&gt; 推送 Harbor</span></span>
<span class="line"><span>  -&gt; Helm / Kustomize 渲染配置</span></span>
<span class="line"><span>  -&gt; kubectl apply 部署到集群</span></span>
<span class="line"><span>  -&gt; 滚动发布</span></span>
<span class="line"><span>  -&gt; 监控和告警</span></span></code></pre></div><h2 id="helm-应用包管理" tabindex="-1">Helm 应用包管理 <a class="header-anchor" href="#helm-应用包管理" aria-label="Permalink to &quot;Helm 应用包管理&quot;">​</a></h2><p>Helm 把一组 K8s 资源打包成可参数化的 Chart，便于多环境复用：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>helm install my-service ./chart -f values-prod.yaml</span></span></code></pre></div><h2 id="灰度发布与服务网格" tabindex="-1">灰度发布与服务网格 <a class="header-anchor" href="#灰度发布与服务网格" aria-label="Permalink to &quot;灰度发布与服务网格&quot;">​</a></h2><p>大型项目在 K8s 之上还会引入流量治理能力：</p><ul><li><code>Istio</code> / <code>Linkerd</code>：服务网格，提供 mTLS、流量镜像、服务间治理。</li><li><code>Argo Rollouts</code>：蓝绿、金丝雀、灰度发布。</li><li><code>Envoy</code>：高性能代理。</li></ul><p>普通中小项目可以先不用服务网格，复杂度较高。简单灰度可以用 <code>Gateway + Nacos</code> 做路由控制。</p>`,15)])])}const b=a(n,[["render",i]]);export{h as __pageData,b as default};
